<?php
declare(strict_types=1); namespace Vigilancia\Exceptions; use Throwable;use Vigilancia\Http\JsonResponse;use Vigilancia\Support\Logger;
final class ErrorHandler{public static function register(bool $debug,string $logFile):void{ini_set('display_errors',$debug?'1':'0');error_reporting(E_ALL);set_exception_handler(static function(Throwable $e)use($debug,$logFile):void{(new Logger($logFile))->error($e->getMessage(),['exception'=>$e::class]);$status=$e instanceof HttpException?$e->status:500;$message=$e instanceof HttpException?$e->getMessage():($debug?$e->getMessage():'Ocurrió un error interno.');if(str_contains($_SERVER['REQUEST_URI']??'','/api'))JsonResponse::error($message,$e instanceof HttpException?$e->errors:[],$status);http_response_code($status);$file=dirname(__DIR__,2).'/public/errors/'.(in_array($status,[403,404],true)?$status:'500').'.php';require $file;});}}
